-- Test dataset bootstrap script for migration validation
-- Execute only the section matching your DB engine.

/* =========================================================
   [SECTION A] MySQL 8.x
   ========================================================= */

CREATE DATABASE IF NOT EXISTS member_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE DATABASE IF NOT EXISTS item_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE DATABASE IF NOT EXISTS cust_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;

USE member_db;

CREATE TABLE IF NOT EXISTS mbr_base (
  id BIGINT PRIMARY KEY,
  member_no VARCHAR(30),
  mbr_name VARCHAR(100),
  resident_no VARCHAR(64),
  mobile_no VARCHAR(30),
  mbr_detail VARCHAR(255),
  mbr_auth VARCHAR(255),
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE IF NOT EXISTS mbr_detail (id BIGINT PRIMARY KEY, email VARCHAR(150), addr_detail VARCHAR(255), note VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS mbr_log_01 (id BIGINT PRIMARY KEY, event_type VARCHAR(40), message VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS mbr_log_02 (id BIGINT PRIMARY KEY, event_type VARCHAR(40), message VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS mbr_log_03 (id BIGINT PRIMARY KEY, event_type VARCHAR(40), message VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS mbr_auth (id BIGINT PRIMARY KEY, auth_code VARCHAR(100), auth_desc VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS mbr_sns (id BIGINT PRIMARY KEY, sns_type VARCHAR(30), sns_id VARCHAR(120), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS mbr_point (id BIGINT PRIMARY KEY, point_amt INT, reason VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS mbr_grade (id BIGINT PRIMARY KEY, grade_code VARCHAR(30), grade_name VARCHAR(100), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS mbr_dormant (id BIGINT PRIMARY KEY, dormant_yn CHAR(1), dormant_at TIMESTAMP NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);

ON DUPLICATE KEY UPDATE mbr_name=VALUES(mbr_name);
ON DUPLICATE KEY UPDATE email=VALUES(email);

USE item_db;
CREATE TABLE IF NOT EXISTS itm_base (id BIGINT PRIMARY KEY, item_no VARCHAR(40), item_name VARCHAR(150), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS itm_price (id BIGINT PRIMARY KEY, price_amt DECIMAL(15,2), currency VARCHAR(10), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS itm_stock (id BIGINT PRIMARY KEY, stock_qty INT, warehouse_cd VARCHAR(30), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS itm_category (id BIGINT PRIMARY KEY, category_cd VARCHAR(40), category_name VARCHAR(100), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS itm_review (id BIGINT PRIMARY KEY, rating INT, review_text VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS itm_qna (id BIGINT PRIMARY KEY, question VARCHAR(255), answer VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS itm_img (id BIGINT PRIMARY KEY, img_url VARCHAR(255), img_type VARCHAR(30), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS itm_display (id BIGINT PRIMARY KEY, display_yn CHAR(1), display_order INT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS itm_vendor (id BIGINT PRIMARY KEY, vendor_cd VARCHAR(40), vendor_name VARCHAR(120), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS itm_discount (id BIGINT PRIMARY KEY, discount_rate DECIMAL(5,2), discount_desc VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);


USE cust_db;
CREATE TABLE IF NOT EXISTS cst_base (id BIGINT PRIMARY KEY, cust_no VARCHAR(30), cust_name VARCHAR(100), cst_phone VARCHAR(40), cst_email VARCHAR(150), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS cst_addr (id BIGINT PRIMARY KEY, zip_no VARCHAR(10), addr1 VARCHAR(150), addr2 VARCHAR(150), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS cst_term (id BIGINT PRIMARY KEY, term_code VARCHAR(30), agree_yn CHAR(1), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS cst_black (id BIGINT PRIMARY KEY, black_yn CHAR(1), reason VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS cst_counsel (id BIGINT PRIMARY KEY, channel VARCHAR(30), contents VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS cst_memo (id BIGINT PRIMARY KEY, memo_text VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS cst_group (id BIGINT PRIMARY KEY, group_cd VARCHAR(30), group_name VARCHAR(100), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS cst_event (id BIGINT PRIMARY KEY, event_cd VARCHAR(40), event_name VARCHAR(120), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS cst_coupon (id BIGINT PRIMARY KEY, coupon_no VARCHAR(40), coupon_desc VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS cst_benefit (id BIGINT PRIMARY KEY, benefit_type VARCHAR(40), benefit_desc VARCHAR(255), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);

ON DUPLICATE KEY UPDATE cust_name=VALUES(cust_name);


/* =========================================================
   [SECTION B] Tibero 6/7
