-- MEMBER_DB
CREATE TABLE MBR_BASE (ID NUMBER PRIMARY KEY, MEMBER_NO VARCHAR2(30), MBR_NAME VARCHAR2(100), RESIDENT_NO VARCHAR2(64), MOBILE_NO VARCHAR2(30), MBR_DETAIL VARCHAR2(255), MBR_AUTH VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE MBR_DETAIL (ID NUMBER PRIMARY KEY, EMAIL VARCHAR2(150), ADDR_DETAIL VARCHAR2(255), NOTE VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE MBR_LOG_01 (ID NUMBER PRIMARY KEY, EVENT_TYPE VARCHAR2(40), MESSAGE VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE MBR_LOG_02 (ID NUMBER PRIMARY KEY, EVENT_TYPE VARCHAR2(40), MESSAGE VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE MBR_LOG_03 (ID NUMBER PRIMARY KEY, EVENT_TYPE VARCHAR2(40), MESSAGE VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE MBR_AUTH (ID NUMBER PRIMARY KEY, AUTH_CODE VARCHAR2(100), AUTH_DESC VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE MBR_SNS (ID NUMBER PRIMARY KEY, SNS_TYPE VARCHAR2(30), SNS_ID VARCHAR2(120), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE MBR_POINT (ID NUMBER PRIMARY KEY, POINT_AMT NUMBER, REASON VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE MBR_GRADE (ID NUMBER PRIMARY KEY, GRADE_CODE VARCHAR2(30), GRADE_NAME VARCHAR2(100), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE MBR_DORMANT (ID NUMBER PRIMARY KEY, DORMANT_YN CHAR(1), DORMANT_AT TIMESTAMP, CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);


-- ITEM_DB
CREATE TABLE ITM_BASE (ID NUMBER PRIMARY KEY, ITEM_NO VARCHAR2(40), ITEM_NAME VARCHAR2(150), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE ITM_PRICE (ID NUMBER PRIMARY KEY, PRICE_AMT NUMBER(15,2), CURRENCY VARCHAR2(10), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE ITM_STOCK (ID NUMBER PRIMARY KEY, STOCK_QTY NUMBER, WAREHOUSE_CD VARCHAR2(30), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE ITM_CATEGORY (ID NUMBER PRIMARY KEY, CATEGORY_CD VARCHAR2(40), CATEGORY_NAME VARCHAR2(100), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE ITM_REVIEW (ID NUMBER PRIMARY KEY, RATING NUMBER, REVIEW_TEXT VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE ITM_QNA (ID NUMBER PRIMARY KEY, QUESTION VARCHAR2(255), ANSWER VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE ITM_IMG (ID NUMBER PRIMARY KEY, IMG_URL VARCHAR2(255), IMG_TYPE VARCHAR2(30), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE ITM_DISPLAY (ID NUMBER PRIMARY KEY, DISPLAY_YN CHAR(1), DISPLAY_ORDER NUMBER, CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE ITM_VENDOR (ID NUMBER PRIMARY KEY, VENDOR_CD VARCHAR2(40), VENDOR_NAME VARCHAR2(120), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE ITM_DISCOUNT (ID NUMBER PRIMARY KEY, DISCOUNT_RATE NUMBER(5,2), DISCOUNT_DESC VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);


-- CUST_DB
CREATE TABLE CST_BASE (ID NUMBER PRIMARY KEY, CUST_NO VARCHAR2(30), CUST_NAME VARCHAR2(100), CST_PHONE VARCHAR2(40), CST_EMAIL VARCHAR2(150), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE CST_ADDR (ID NUMBER PRIMARY KEY, ZIP_NO VARCHAR2(10), ADDR1 VARCHAR2(150), ADDR2 VARCHAR2(150), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE CST_TERM (ID NUMBER PRIMARY KEY, TERM_CODE VARCHAR2(30), AGREE_YN CHAR(1), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE CST_BLACK (ID NUMBER PRIMARY KEY, BLACK_YN CHAR(1), REASON VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE CST_COUNSEL (ID NUMBER PRIMARY KEY, CHANNEL VARCHAR2(30), CONTENTS VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE CST_MEMO (ID NUMBER PRIMARY KEY, MEMO_TEXT VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE CST_GROUP (ID NUMBER PRIMARY KEY, GROUP_CD VARCHAR2(30), GROUP_NAME VARCHAR2(100), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE CST_EVENT (ID NUMBER PRIMARY KEY, EVENT_CD VARCHAR2(40), EVENT_NAME VARCHAR2(120), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE CST_COUPON (ID NUMBER PRIMARY KEY, COUPON_NO VARCHAR2(40), COUPON_DESC VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE CST_BENEFIT (ID NUMBER PRIMARY KEY, BENEFIT_TYPE VARCHAR2(40), BENEFIT_DESC VARCHAR2(255), CREATED_AT TIMESTAMP DEFAULT CURRENT_TIMESTAMP);


COMMIT;

/* =========================================================
   [SECTION C] Bulk seed to 100 rows per table
   - Existing ID=1 row is preserved.
   - This section adds ID 2..100.
   ========================================================= */

/* ---------- C-1. MySQL 8.x (ID 2..100) ---------- */

SELECT n, CONCAT('M', LPAD(n, 4, '0')), CONCAT('Kim DA ', n), CONCAT('900101-', LPAD(n, 7, '0')), CONCAT('010', LPAD(n, 8, '0')), CONCAT('damo_payload_', LPAD(n, 3, '0')), CONCAT('damo_auth_', LPAD(n, 3, '0'))
FROM (SELECT 2 n UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9 UNION ALL SELECT 10
      UNION ALL SELECT 11 UNION ALL SELECT 12 UNION ALL SELECT 13 UNION ALL SELECT 14 UNION ALL SELECT 15 UNION ALL SELECT 16 UNION ALL SELECT 17 UNION ALL SELECT 18 UNION ALL SELECT 19 UNION ALL SELECT 20
