INSERT INTO member_db.mbr_base (id, member_no, mbr_name, resident_no, mobile_no, mbr_detail, mbr_auth)
INSERT INTO member_db.mbr_detail (id, email, addr_detail, note) SELECT id, CONCAT('member', id, '@example.com'), CONCAT('Seoul Test-gu ', id), CONCAT('seed_', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO member_db.mbr_log_01 (id, event_type, message) SELECT id, 'LOGIN', CONCAT('seed_', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO member_db.mbr_log_02 (id, event_type, message) SELECT id, 'LOGIN', CONCAT('seed_', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO member_db.mbr_log_03 (id, event_type, message) SELECT id, 'LOGIN', CONCAT('seed_', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO member_db.mbr_auth (id, auth_code, auth_desc) SELECT id, CONCAT('ROLE_', id), CONCAT('seed_', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO member_db.mbr_sns (id, sns_type, sns_id) SELECT id, 'KAKAO', CONCAT('kakao_', LPAD(id, 3, '0')) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO member_db.mbr_point (id, point_amt, reason) SELECT id, id * 10, CONCAT('seed_', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO member_db.mbr_grade (id, grade_code, grade_name) SELECT id, CONCAT('G', LPAD(id, 3, '0')), CONCAT('Grade ', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO member_db.mbr_dormant (id, dormant_yn, dormant_at) SELECT id, 'N', NULL FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO item_db.itm_base (id, item_no, item_name) SELECT id, CONCAT('I', LPAD(id, 4, '0')), CONCAT('Seed Item ', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO item_db.itm_price (id, price_amt, currency) SELECT id, 1000 + (id * 100), 'KRW' FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO item_db.itm_stock (id, stock_qty, warehouse_cd) SELECT id, 100 + id, CONCAT('WH', LPAD((id % 10) + 1, 2, '0')) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO item_db.itm_category (id, category_cd, category_name) SELECT id, CONCAT('C', LPAD((id % 20) + 1, 3, '0')), CONCAT('Category ', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO item_db.itm_review (id, rating, review_text) SELECT id, ((id - 1) % 5) + 1, CONCAT('seed_review_', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO item_db.itm_qna (id, question, answer) SELECT id, CONCAT('seed question ', id), CONCAT('seed answer ', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO item_db.itm_img (id, img_url, img_type) SELECT id, CONCAT('https://example.com/', id, '.jpg'), 'MAIN' FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO item_db.itm_display (id, display_yn, display_order) SELECT id, 'Y', id FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO item_db.itm_vendor (id, vendor_cd, vendor_name) SELECT id, CONCAT('V', LPAD((id % 15) + 1, 3, '0')), CONCAT('Vendor ', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO item_db.itm_discount (id, discount_rate, discount_desc) SELECT id, (id % 30), CONCAT('seed_discount_', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO cust_db.cst_base (id, cust_no, cust_name, cst_phone, cst_email) SELECT id, CONCAT('C', LPAD(id, 4, '0')), CONCAT('Lee Cust ', id), CONCAT('010', LPAD(70000000 + id, 8, '0')), CONCAT('cust', id, '@example.com') FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO cust_db.cst_addr (id, zip_no, addr1, addr2) SELECT id, LPAD(60000 + id, 5, '0'), 'Seoul', CONCAT('Test-ro ', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO cust_db.cst_term (id, term_code, agree_yn) SELECT id, CONCAT('T', LPAD((id % 20) + 1, 3, '0')), 'Y' FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO cust_db.cst_black (id, black_yn, reason) SELECT id, 'N', CONCAT('seed_', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO cust_db.cst_counsel (id, channel, contents) SELECT id, 'CALL', CONCAT('seed_', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO cust_db.cst_memo (id, memo_text) SELECT id, CONCAT('seed_', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO cust_db.cst_group (id, group_cd, group_name) SELECT id, CONCAT('GRP', (id % 10) + 1), CONCAT('Group ', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO cust_db.cst_event (id, event_cd, event_name) SELECT id, CONCAT('EVT', (id % 20) + 1), CONCAT('Event ', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO cust_db.cst_coupon (id, coupon_no, coupon_desc) SELECT id, CONCAT('CPN', LPAD(id, 4, '0')), CONCAT('seed_', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO cust_db.cst_benefit (id, benefit_type, benefit_desc) SELECT id, 'POINT', CONCAT('seed_', id) FROM member_db.mbr_base WHERE id BETWEEN 2 AND 100;
INSERT INTO MBR_BASE (ID, MEMBER_NO, MBR_NAME, RESIDENT_NO, MOBILE_NO, MBR_DETAIL, MBR_AUTH)
INSERT INTO MBR_DETAIL (ID, EMAIL, ADDR_DETAIL, NOTE) SELECT LEVEL, 'member' || LEVEL || '@example.com', 'Seoul Test-gu ' || LEVEL, 'seed_' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO MBR_LOG_01 (ID, EVENT_TYPE, MESSAGE) SELECT LEVEL, 'LOGIN', 'seed_' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO MBR_LOG_02 (ID, EVENT_TYPE, MESSAGE) SELECT LEVEL, 'LOGIN', 'seed_' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO MBR_LOG_03 (ID, EVENT_TYPE, MESSAGE) SELECT LEVEL, 'LOGIN', 'seed_' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO MBR_AUTH (ID, AUTH_CODE, AUTH_DESC) SELECT LEVEL, 'ROLE_' || LEVEL, 'seed_' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO MBR_SNS (ID, SNS_TYPE, SNS_ID) SELECT LEVEL, 'KAKAO', 'kakao_' || LPAD(LEVEL, 3, '0') FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO MBR_POINT (ID, POINT_AMT, REASON) SELECT LEVEL, LEVEL * 10, 'seed_' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO MBR_GRADE (ID, GRADE_CODE, GRADE_NAME) SELECT LEVEL, 'G' || LPAD(LEVEL, 3, '0'), 'Grade ' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO MBR_DORMANT (ID, DORMANT_YN, DORMANT_AT) SELECT LEVEL, 'N', NULL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO ITM_BASE (ID, ITEM_NO, ITEM_NAME) SELECT LEVEL, 'I' || LPAD(LEVEL, 4, '0'), 'Seed Item ' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO ITM_PRICE (ID, PRICE_AMT, CURRENCY) SELECT LEVEL, 1000 + (LEVEL * 100), 'KRW' FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO ITM_STOCK (ID, STOCK_QTY, WAREHOUSE_CD) SELECT LEVEL, 100 + LEVEL, 'WH' || LPAD(MOD(LEVEL, 10) + 1, 2, '0') FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO ITM_CATEGORY (ID, CATEGORY_CD, CATEGORY_NAME) SELECT LEVEL, 'C' || LPAD(MOD(LEVEL, 20) + 1, 3, '0'), 'Category ' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO ITM_REVIEW (ID, RATING, REVIEW_TEXT) SELECT LEVEL, MOD(LEVEL - 1, 5) + 1, 'seed_review_' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO ITM_QNA (ID, QUESTION, ANSWER) SELECT LEVEL, 'seed question ' || LEVEL, 'seed answer ' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO ITM_IMG (ID, IMG_URL, IMG_TYPE) SELECT LEVEL, 'https://example.com/' || LEVEL || '.jpg', 'MAIN' FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO ITM_DISPLAY (ID, DISPLAY_YN, DISPLAY_ORDER) SELECT LEVEL, 'Y', LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO ITM_VENDOR (ID, VENDOR_CD, VENDOR_NAME) SELECT LEVEL, 'V' || LPAD(MOD(LEVEL, 15) + 1, 3, '0'), 'Vendor ' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO ITM_DISCOUNT (ID, DISCOUNT_RATE, DISCOUNT_DESC) SELECT LEVEL, MOD(LEVEL, 30), 'seed_discount_' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO CST_BASE (ID, CUST_NO, CUST_NAME, CST_PHONE, CST_EMAIL) SELECT LEVEL, 'C' || LPAD(LEVEL, 4, '0'), 'Lee Cust ' || LEVEL, '010' || LPAD(70000000 + LEVEL, 8, '0'), 'cust' || LEVEL || '@example.com' FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO CST_ADDR (ID, ZIP_NO, ADDR1, ADDR2) SELECT LEVEL, LPAD(60000 + LEVEL, 5, '0'), 'Seoul', 'Test-ro ' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO CST_TERM (ID, TERM_CODE, AGREE_YN) SELECT LEVEL, 'T' || LPAD(MOD(LEVEL, 20) + 1, 3, '0'), 'Y' FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO CST_BLACK (ID, BLACK_YN, REASON) SELECT LEVEL, 'N', 'seed_' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO CST_COUNSEL (ID, CHANNEL, CONTENTS) SELECT LEVEL, 'CALL', 'seed_' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO CST_MEMO (ID, MEMO_TEXT) SELECT LEVEL, 'seed_' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO CST_GROUP (ID, GROUP_CD, GROUP_NAME) SELECT LEVEL, 'GRP' || (MOD(LEVEL, 10) + 1), 'Group ' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO CST_EVENT (ID, EVENT_CD, EVENT_NAME) SELECT LEVEL, 'EVT' || (MOD(LEVEL, 20) + 1), 'Event ' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO CST_COUPON (ID, COUPON_NO, COUPON_DESC) SELECT LEVEL, 'CPN' || LPAD(LEVEL, 4, '0'), 'seed_' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
INSERT INTO CST_BENEFIT (ID, BENEFIT_TYPE, BENEFIT_DESC) SELECT LEVEL, 'POINT', 'seed_' || LEVEL FROM dual CONNECT BY LEVEL <= 99;
